final repoProvider=Provider((ref)=>ApiRepository(ref.watch(dioProvider)));
final sessionProvider=AsyncNotifierProvider<Session,String?>(Session.new);
class Session extends AsyncNotifier<String?>{String? nickname;@override Future<String?> build()async{ref.watch(authExpiredProvider);final store=ref.read(sessionStoreProvider);await store.migrateLegacyIfNeeded();final id=await store.userId();nickname=await store.nickname();final token=await store.accessToken();if(id!=null&&token!=null){try{final u=await ref.read(repoProvider).me();nickname=u.nickname;return u.id;}catch(_){await store.clearUserSession();}}return null;}Future<void> start(String n)async{state=const AsyncLoading();state=await AsyncValue.guard(()async{final store=ref.read(sessionStoreProvider);final installationId=await store.installationId();final r=await ref.read(repoProvider).createGuest(n.trim(),installationId);await store.saveUser(userId:r.user.id,nickname:r.user.nickname,accessToken:r.accessToken);nickname=r.user.nickname;return r.user.id;});}Future<void> logout()async{final store=ref.read(sessionStoreProvider);try{await ref.read(repoProvider).logout();}catch(_){}await store.clearUserSession();await store.installationId();state=const AsyncData(null);}}
