class BattleScreen extends ConsumerStatefulWidget{const BattleScreen({super.key});@override ConsumerState<BattleScreen> createState()=>_BattleScreenState();}class _BattleScreenState extends ConsumerState<BattleScreen>{bool voting=false;Future<void> vote(Battle b,String w)async{if(voting)return;setState(()=>voting=true);try{final r=await ref.read(repoProvider).vote(b,w);final win=r['winner'] as Map;final delta=(win['ratingAfter'] as int)-(win['ratingBefore'] as int);if(mounted){final pred=(r['prediction'] as Map?)??{};ScaffoldMessenger.of(context).showSnackBar(SnackBar(content:Text(pred['created']==true?'Прогноз сохранён — если мем станет хитом, ты получишь очки скаута':'Голос учтён: +$delta рейтинга победителю')));}ref.invalidate(battleProvider);}catch(e){if(mounted)ScaffoldMessenger.of(context).showSnackBar(SnackBar(content:Text(e.toString())));}finally{if(mounted)setState(()=>voting=false);}}@override Widget build(c){final b=ref.watch(battleProvider);return SafeArea(child:b.when(loading:()=>const Center(child:CircularProgressIndicator()),error:(e,_)=>Center(child:Column(mainAxisSize:MainAxisSize.min,children:[Text('Ошибка: $e'),FilledButton(onPressed:()=>ref.invalidate(battleProvider),child:const Text('Повторить'))])),data:(v)=>v==null?Center(child:Column(mainAxisSize:MainAxisSize.min,children:[const Text('Ты проголосовал за все доступные пары'),FilledButton(onPressed:()=>ref.invalidate(battleProvider),child:const Text('Обновить'))])):ListView(padding:const EdgeInsets.all(16),children:[Text('Какой мем смешнее?',style:Theme.of(context).textTheme.headlineMedium,textAlign:TextAlign.center),MemeCard(m:v.left,onTap:()=>vote(v,v.left.id),disabled:voting),const Center(child:Text('VS')),MemeCard(m:v.right,onTap:()=>vote(v,v.right.id),disabled:voting)])));}}
class MemeCard extends StatelessWidget{const MemeCard({super.key,required this.m,this.onTap,this.disabled=false});final MemeItem m;final VoidCallback? onTap;final bool disabled;@override Widget build(c)=>Card(clipBehavior:Clip.antiAlias,child:InkWell(onTap:disabled?null:onTap,child:Column(children:[AspectRatio(aspectRatio:4/3,child:CachedNetworkImage(imageUrl:m.imageUrl,fit:BoxFit.cover,placeholder:(_,__)=>const Center(child:CircularProgressIndicator()),errorWidget:(_,__,___)=>const Center(child:Icon(Icons.broken_image,size:48)))),ListTile(title:Text(m.title),subtitle:Text('Рейтинг ${m.rating}'))])));}
