class _ScoutTop extends ConsumerWidget{const _ScoutTop(this.period,{required this.onChanged});final String period;final ValueChanged<String> onChanged;@override Widget build(c,ref){final me=ref.watch(sessionProvider).value;final a=ref.watch(scoutTopProvider(period));return Expanded(child:Column(children:[SegmentedButton<String>(segments:const [ButtonSegment(value:'WEEK',label:Text('Неделя')),ButtonSegment(value:'ALL_TIME',label:Text('Всё время'))],selected:{period},onSelectionChanged:(s)=>onChanged(s.first)),Expanded(child:a.when(loading:()=>const Center(child:CircularProgressIndicator()),error:(e,_)=>Center(child:Text('Ошибка: $e')),data:(items)=>ListView.builder(itemCount:items.length,itemBuilder:(c,n){final x=items[n];final mine=x.userId==me;return ListTile(tileColor:mine?Theme.of(c).colorScheme.primaryContainer:null,leading:Text('${x.position}'),title:Text(x.nickname),subtitle:Text('${rankLabel(x.rank)} · ${x.scoutPoints} очков'),trailing:Text(accuracyLabel(x.accuracy)));}))) ]));}}
class UploadScreen extends ConsumerStatefulWidget{const UploadScreen({super.key});@override ConsumerState<UploadScreen> createState()=>_UploadScreenState();}class _UploadScreenState extends ConsumerState<UploadScreen>{final title=TextEditingController(),src=TextEditingController();String? path,msg;@override Widget build(c)=>SafeArea(child:ListView(padding:const EdgeInsets.all(16),children:[const Text('Загрузка мема'),OutlinedButton(onPressed:()async{final x=await ImagePicker().pickImage(source:ImageSource.gallery);if(x!=null)setState(()=>path=x.path);},child:Text(path==null?'Выбрать изображение':'Изображение выбрано')),if(path!=null)Padding(padding:const EdgeInsets.symmetric(vertical:12),child:Image.file(File(path!),height:180,fit:BoxFit.cover)),TextField(controller:title,decoration:const InputDecoration(labelText:'Название')),TextField(controller:src,decoration:const InputDecoration(labelText:'URL источника (необязательно)')),FilledButton(onPressed:path==null||title.text.trim().isEmpty?null:()async{final f=File(path!);final ext=path!.split('.').last.toLowerCase();if(!['jpg','jpeg','png','webp'].contains(ext)){setState(()=>msg='Поддерживаются JPEG, PNG и WebP');return;}if(await f.length()>10*1024*1024){setState(()=>msg='Файл слишком большой');return;}try{final media=await ref.read(repoProvider).upload(f);await ref.read(repoProvider).createMeme(title.text.trim(),media,src.text.trim());setState(()=>msg='Мем отправлен на модерацию');title.clear();src.clear();path=null;}catch(e){setState(()=>msg=e.toString());}},child:const Text('Отправить на модерацию')),if(msg!=null)Text(msg!)]));}
